-- FounderHub NL — Supabase schema
-- Run this in your Supabase SQL editor

-- 1. Initiatives
create table if not exists initiatives (
  id integer primary key,
  name text not null,
  type text not null,
  secondary_type text default '',
  url text default '',
  organization text default '',
  access text default 'Application required',
  cost text default 'Free',
  notes text default '',
  province text default '',
  city text default '',
  industries jsonb default '[]',
  format text default '',
  updated_at timestamptz default now()
);

-- 2. Admin sessions
create table if not exists admin_sessions (
  token text primary key,
  expires_at timestamptz not null,
  created_at timestamptz default now()
);

-- 3. Claim requests
create table if not exists claims (
  id uuid primary key default gen_random_uuid(),
  initiative_id integer not null references initiatives(id),
  initiative_name text not null,
  claimant_name text not null,
  claimant_email text not null,
  claimant_org text default '',
  reason text default '',
  status text default 'pending',
  created_at timestamptz default now()
);

-- 4. Approved claimants
create table if not exists claimants (
  id uuid primary key default gen_random_uuid(),
  email text unique not null,
  password_hash text not null,
  initiative_ids integer[] default '{}',
  created_at timestamptz default now()
);

-- 5. Claimant sessions
create table if not exists claimant_sessions (
  token text primary key,
  claimant_id uuid not null references claimants(id),
  expires_at timestamptz not null
);

-- Disable RLS on all tables (these are accessed via service role key only)
alter table initiatives disable row level security;
alter table admin_sessions disable row level security;
alter table claims disable row level security;
alter table claimants disable row level security;
alter table claimant_sessions disable row level security;

-- Allow public read on initiatives only
alter table initiatives enable row level security;
create policy "Public read initiatives" on initiatives for select using (true);

-- ─── SEED DATA ───────────────────────────────────────────────────────────────
on conflict (id) do nothing;
